Create a new reusable hook at `apps/client/src/layers/entities/session/model/use-rename-session.ts` that wraps `useMutation` from TanStack Query with optimistic updates for session title renames.

**New file:** `apps/client/src/layers/entities/session/model/use-rename-session.ts`

**Full implementation:**
```ts
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { toast } from 'sonner';
import { useTransport } from '@/layers/shared/model';
import type { Session } from '@dorkos/shared/types';

/**
 * Optimistic rename mutation for sessions.
 *
 * Updates the title instantly in the query cache, then persists via
 * `transport.updateSession`. On error the cache is rolled back and a
 * toast is shown.
 *
 * @param cwd - Current working directory (agent path) used as the sessions query key segment.
 */
export function useRenameSession(cwd: string | null) {
  const transport = useTransport();
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({ sessionId, title }: { sessionId: string; title: string }) =>
      transport.updateSession(sessionId, { title }, cwd ?? undefined),

    onMutate: async ({ sessionId, title }) => {
      // Cancel any in-flight session queries so they don't overwrite our optimistic update
      await queryClient.cancelQueries({ queryKey: ['sessions'] });

      // Snapshot the previous value for rollback
      const previous = queryClient.getQueryData<Session[]>(['sessions', cwd]);

      // Optimistically update the cache
      queryClient.setQueryData<Session[]>(['sessions', cwd], (old) =>
        old?.map((s) => (s.id === sessionId ? { ...s, title } : s))
      );

      return { previous };
    },

    onError: (_err, _vars, context) => {
      // Roll back to the previous cache state
      if (context?.previous) {
        queryClient.setQueryData(['sessions', cwd], context.previous);
      }
      toast.error('Failed to rename session');
    },

    onSettled: () => {
      // Always refetch after mutation to ensure cache consistency
      queryClient.invalidateQueries({ queryKey: ['sessions'] });
    },
  });
}
```

**Export from barrel files:**

1. Add to `apps/client/src/layers/entities/session/index.ts` after the existing exports (e.g., after the `usePulseMotion` export on line 27):
```ts
export { useRenameSession } from './model/use-rename-session';
```

**How the optimistic update works:**
1. `onMutate` runs before the mutation function — it cancels in-flight `['sessions']` queries, snapshots the current cache, and applies the title change immediately
2. The UI sees the updated title instantly (no loading spinner)
3. If `transport.updateSession` fails, `onError` rolls back the cache to the snapshot and shows an error toast
4. `onSettled` always invalidates `['sessions']` to refetch the authoritative server state

**Query key structure:** The sessions are cached under `['sessions', cwd]` where `cwd` is the agent directory path. The `cancelQueries` call uses the broader `['sessions']` prefix to cancel any related queries.

**Usage pattern (for consumers in tasks 2.2, 3.1, 4.1):**
```ts
const renameSession = useRenameSession(selectedCwd);

const handleRenameSession = useCallback(
  (sessionId: string, title: string) => {
    renameSession.mutate({ sessionId, title });
  },
  [renameSession]
);
```

**Acceptance criteria:**
- Hook compiles with no TypeScript errors
- `mutate({ sessionId, title })` optimistically updates the session title in the query cache
- On error, the cache rolls back to the previous state and a toast appears saying 'Failed to rename session'
- On success or failure, `['sessions']` queries are invalidated to refetch
- The hook is exported from `entities/session/index.ts`
- The hook follows FSD rules: entities layer importing from shared (useTransport, types)

