**Updated implementation:**
```tsx
import { useMemo, useCallback } from 'react';
import { toast } from 'sonner';
import { useQueryClient } from '@tanstack/react-query';
import { groupSessionsByTime } from '@/layers/shared/lib';
import { useTransport } from '@/layers/shared/model';
import { useSessions, useRenameSession } from '@/layers/entities/session';
import { useAgentToolStatus } from '@/layers/entities/agent';
import { SessionsView, TasksView } from '@/layers/features/session-list';
import { useAgentHubContext } from '../../model/agent-hub-context';

/**
 * Sessions tab for the Agent Hub panel.
 *
 * Unified view composing scheduled tasks (from the former TasksTab) at the top
 * and grouped sessions below. Tasks section only appears when the agent has
 * scheduled tasks enabled.
 */
export function SessionsTab() {
  const { agent, projectPath } = useAgentHubContext();
  const { sessions, activeSessionId, setActiveSession } = useSessions();
  const toolStatus = useAgentToolStatus(projectPath);
  const transport = useTransport();
  const queryClient = useQueryClient();

  const agentSessions = useMemo(
    () =>
      sessions
        .filter((s) => s.cwd === projectPath)
        .sort((a, b) => b.updatedAt.localeCompare(a.updatedAt)),
    [sessions, projectPath]
  );

  const groupedSessions = useMemo(() => groupSessionsByTime(agentSessions), [agentSessions]);

  // ── Fork handler ──
  const handleForkSession = useCallback(
    async (sessionId: string) => {
      try {
        const forked = await transport.forkSession(sessionId, undefined, projectPath);
        await queryClient.invalidateQueries({ queryKey: ['sessions'] });
        setActiveSession(forked.id);
      } catch (err) {
        toast.error(err instanceof Error ? err.message : 'Failed to fork session');
      }
    },
    [transport, projectPath, queryClient, setActiveSession]
  );

  // ── Rename handler (optimistic) ──
  const renameSession = useRenameSession(projectPath);

  const handleRenameSession = useCallback(
    (sessionId: string, title: string) => {
      renameSession.mutate({ sessionId, title });
    },
    [renameSession]
  );

  return (
    <div className="flex flex-col">
      {toolStatus.tasks === 'enabled' && (
        <div className="border-b">
          <TasksView toolStatus={toolStatus.tasks} agentId={agent.id} />
        </div>
      )}
      <SessionsView
        activeSessionId={activeSessionId}
        groupedSessions={groupedSessions}
        onSessionClick={setActiveSession}
        onForkSession={handleForkSession}
        onRenameSession={handleRenameSession}
      />
    </div>
  );
}
```

**Changes summary:**
1. Add imports: `useCallback` from react, `toast` from sonner, `useQueryClient` from tanstack, `useTransport` from shared/model, `useRenameSession` from entities/session
2. Add `transport` and `queryClient` hooks at the top of the component
3. Add `handleForkSession` callback that forks the session via transport, invalidates queries, and navigates to the forked session via `setActiveSession(forked.id)`. Shows error toast on failure.
4. Add `renameSession` mutation and `handleRenameSession` wrapper callback
5. Pass `onForkSession={handleForkSession}` and `onRenameSession={handleRenameSession}` to `SessionsView`

**FSD compliance:** `SessionsTab` is in `features/agent-hub` and imports from:
- `shared/lib` (groupSessionsByTime) -- allowed
- `shared/model` (useTransport) -- allowed
- `entities/session` (useSessions, useRenameSession) -- allowed
- `entities/agent` (useAgentToolStatus) -- allowed
- `features/session-list` (SessionsView, TasksView) -- UI composition between features, allowed per FSD rules

**Fork navigation behavior:** In the Agent Hub, fork uses `setActiveSession(forked.id)` (from `useSessions`) which updates the active session ID in the sessions context. This differs from `DashboardSidebar` which uses `navigate()` — the Agent Hub is a right-side panel, so it updates session selection rather than routing.

**Acceptance criteria:**
- Right-clicking a session row in the Agent Hub's Sessions tab shows a context menu with Rename and Fork options
- Fork creates a new session and selects it as active in the Agent Hub
- Fork shows error toast on failure
- Rename is optimistic — title updates instantly, rolls back on error
- On mobile, long-press on a session row opens a drawer with the same options
- TypeScript compiles with no errors
- The Tasks section at the top is not affected
